import { useContext, useEffect, useState } from "react";
import { AuthContext } from "../AuthContext";
import EventTable from "../Events/EventTable";
import "../styles/Profile.css";

export default function ProfilePage() {
    const { user } = useContext(AuthContext);

    const [profile, setProfile] = useState(null);
    const [events, setEvents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [activeTab, setActiveTab] = useState("overview"); // NEW

    useEffect(() => {
        if (!user?.email) return;

        setLoading(true);

        Promise.all([
            fetch(`/api/me/profile?email=${encodeURIComponent(user.email)}`)
                .then(r => r.ok ? r.json() : Promise.reject()),
            fetch(`/api/me/events?email=${encodeURIComponent(user.email)}`)
                .then(r => r.ok ? r.json() : Promise.reject())
        ])
            .then(([profileData, eventsData]) => {
                setProfile(profileData);
                setEvents(eventsData);
                setLoading(false);
            })
            .catch(() => {
                setError("Failed to load profile");
                setLoading(false);
            });
    }, [user]);

    if (!user) {
        return <div className="profile-page">Please log in</div>;
    }

    if (loading) {
        return <div className="profile-page">Loading profile…</div>;
    }

    if (error) {
        return <div className="profile-page error">{error}</div>;
    }

    return (
        <div className="profile-page">
            <ProfileHeader profile={profile} />

            {/* Tabs */}
            <div className="profile-tabs">
                <TabButton
                    label="Overview"
                    active={activeTab === "overview"}
                    onClick={() => setActiveTab("overview")}
                />
                <TabButton
                    label="Events"
                    active={activeTab === "events"}
                    onClick={() => setActiveTab("events")}
                />
                <TabButton
                    label="Badges"
                    active={activeTab === "badges"}
                    onClick={() => setActiveTab("badges")}
                />
            </div>

            {/* Tab Content */}
            <div className="profile-tab-content">
                {activeTab === "overview" && (
                    <OverviewTab profile={profile} />
                )}

                {activeTab === "events" && (
                    <EventTable events={events} showClub />
                )}

                {activeTab === "badges" && (
                    <div className="muted">Badges coming soon</div>
                )}
            </div>
        </div>
    );
}

/* ───────────────────────────────────────── */

function ProfileHeader({ profile }) {
    return (
        <div className="profile-header">
            <div className="profile-avatar">
                {profile.avatarUrl ? (
                    <img src={profile.avatarUrl} alt="avatar" />
                ) : (
                    <div className="avatar-placeholder">
                        {(profile.displayName || profile.username)[0]}
                    </div>
                )}
            </div>

            <div className="profile-info">
                <h1>{profile.displayName || profile.username}</h1>
                <p className="profile-role">{profile.role}</p>
                {profile.bio && <p className="profile-bio">{profile.bio}</p>}
            </div>
        </div>
    );
}

function OverviewTab({ profile }) {
    return (
        <div className="profile-overview">
            <div className="profile-stats">
                <div>
                    <strong>{profile.eventsJoined}</strong>
                    <span>Events Joined</span>
                </div>
                <div>
                    <strong>{profile.participationScore}</strong>
                    <span>Participation Score</span>
                </div>
            </div>
        </div>
    );
}

function TabButton({ label, active, onClick }) {
    return (
        <button
            className={`profile-tab ${active ? "active" : ""}`}
            onClick={onClick}
        >
            {label}
        </button>
    );
}
